// Network Configuration
import okhttp3.OkHttpClient;
import okhttp3.logging.HttpLoggingInterceptor;
import retrofit2.Retrofit;
import retrofit2.converter.gson.GsonConverterFactory;

public class NetworkConfig {
    private static final String BASE_URL_DEV = "https://dev.api.example.com";
    private static final String BASE_URL_STAGING = "https://staging.api.example.com";
    private static final String BASE_URL_PROD = "https://api.example.com";

    public static Retrofit getRetrofit(String environment) {
        String baseUrl;
        switch (environment.toLowerCase()) {
            case "development":
                baseUrl = BASE_URL_DEV;
                break;
            case "staging":
                baseUrl = BASE_URL_STAGING;
                break;
            case "production":
            default:
                baseUrl = BASE_URL_PROD;
                break;
        }

        HttpLoggingInterceptor logging = new HttpLoggingInterceptor();
        logging.setLevel(HttpLoggingInterceptor.Level.BODY);

        OkHttpClient client = new OkHttpClient.Builder()
                .addInterceptor(logging)
                .build();

        return new Retrofit.Builder()
                .baseUrl(baseUrl)
                .client(client)
                .addConverterFactory(GsonConverterFactory.create())
                .build();
    }
}

// Main Activity
import android.os.Bundle;
import android.widget.Toast;
import androidx.appcompat.app.AppCompatActivity;
import retrofit2.Call;
import retrofit2.Callback;
import retrofit2.Response;

import java.util.List;

public class MainActivity extends AppCompatActivity {
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        Retrofit retrofit = NetworkConfig.getRetrofit("production");
        UserService userService = retrofit.create(UserService.class);

        Call<List<User>> call = userService.getUsers();
        call.enqueue(new Callback<List<User>>() {
            @Override
            public void onResponse(Call<List<User>> call, Response<List<User>> response) {
                if(response.isSuccessful() && response.body() != null) {
                    List<User> users = response.body();
                    Toast.makeText(MainActivity.this, "Fetched " + users.size() + " users", Toast.LENGTH_SHORT).show();
                }
            }

            @Override
            public void onFailure(Call<List<User>> call, Throwable t) {
                Toast.makeText(MainActivity.this, "Error: " + t.getMessage(), Toast.LENGTH_SHORT).show();
            }
        });
    }
}